What is the output of the following code?

class Calculator:
    count = 0

    def __init__(self):
        Calculator.count += 1

    @classmethod
    def get_count(cls):
        return cls.count

    @staticmethod
    def add(a, b):
        return a + b

c1 = Calculator()
c2 = Calculator()
c3 = Calculator()
print(Calculator.get_count())
print(c1.add(5, 3))

What will be the output of the following code demonstrating method resolution?

class A:
    def greet(self):
        return "Hello from A"

class B(A):
    def greet(self):
        return "Hello from B"

class C(A):
    def greet(self):
        return "Hello from C"

class D(B, C):
    pass

obj = D()
print(obj.greet())

Consider the following code using property decorator:

class BankAccount:
    def __init__(self, balance):
        self.__balance = balance

    @property
    def balance(self):
        return self.__balance

    @balance.setter
    def balance(self, value):
        if value >= 0:
            self.__balance = value
        else:
            raise ValueError("Balance cannot be negative")

account = BankAccount(1000)
account.balance = 500
print(account.balance)
account.balance = -100

What does Python output for the following code demonstrating polymorphism?

class Cat:
    def speak(self):
        return "Meow"

class Dog:
    def speak(self):
        return "Woof"

def make_speak(animal):
    print(animal.speak())

make_speak(Cat())
make_speak(Dog())

If we add:
make_speak("I am a string")

What will be printed by the following code involving class inheritance and super()? 

class Person:
    def __init__(self, name):
        self.name = name
        print(f"Person created: {self.name}")

class Student(Person):
    def __init__(self, name, grade):
        super().__init__(name)
        self.grade = grade
        print(f"Student created: {self.name}, Grade: {self.grade}")

class Teacher(Person):
    def __init__(self, name, subject):
        super().__init__(name)
        self.subject = subject
        print(f"Teacher created: {self.name}, Subject: {self.subject}")

s = Student("Alice", "A")
t = Teacher("Bob", "Mathematics")
print(isinstance(s, Person), isinstance(t, Person))
